import React, { useState } from 'react';
import { Post } from '../types';
import { Heart, MessageCircle, Repeat2, Share2, MoreHorizontal } from 'lucide-react';

interface PostCardProps {
  post: Post;
}

const PostCard: React.FC<PostCardProps> = ({ post }) => {
  const [liked, setLiked] = useState(false);
  const [likesCount, setLikesCount] = useState(post.likes);

  const handleLike = () => {
    if (liked) {
      setLikesCount(prev => prev - 1);
    } else {
      setLikesCount(prev => prev + 1);
    }
    setLiked(!liked);
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4 mb-4 transition-shadow hover:shadow-sm">
      <div className="flex items-start justify-between mb-4">
        <div className="flex gap-3">
          <img 
            src={post.user.avatar} 
            alt={post.user.name} 
            className="w-12 h-12 rounded-lg object-cover"
          />
          <div>
            <h3 className="font-bold text-slate-900 leading-tight">{post.user.name}</h3>
            <p className="text-xs text-slate-500 font-medium">@{post.user.username} • {post.timestamp}</p>
            <p className="text-[10px] text-slate-400 mt-0.5">{post.user.role} @ {post.user.company}</p>
          </div>
        </div>
        <button className="text-slate-400 hover:text-slate-600 transition-colors">
          <MoreHorizontal className="w-5 h-5" />
        </button>
      </div>

      <div className="mb-4">
        <p className="text-sm text-slate-800 leading-relaxed whitespace-pre-wrap">
          {post.content}
        </p>
        <div className="flex flex-wrap gap-1 mt-2">
          {post.tags.map(tag => (
            <span key={tag} className="text-xs text-blue-600 font-medium hover:underline cursor-pointer">
              #{tag}
            </span>
          ))}
        </div>
      </div>

      {post.image && (
        <div className="mb-4 rounded-xl overflow-hidden border border-slate-100">
          <img src={post.image} alt="Post media" className="w-full h-auto object-cover max-h-[400px]" />
        </div>
      )}

      <div className="flex items-center justify-between pt-4 border-t border-slate-50">
        <button 
          onClick={handleLike}
          className={`flex items-center gap-1.5 transition-colors ${liked ? 'text-rose-500' : 'text-slate-500 hover:text-rose-500'}`}
        >
          <Heart className={`w-5 h-5 ${liked ? 'fill-current' : ''}`} />
          <span className="text-xs font-semibold">{likesCount}</span>
        </button>

        <button className="flex items-center gap-1.5 text-slate-500 hover:text-blue-500 transition-colors">
          <MessageCircle className="w-5 h-5" />
          <span className="text-xs font-semibold">{post.comments}</span>
        </button>

        <button className="flex items-center gap-1.5 text-slate-500 hover:text-green-500 transition-colors">
          <Repeat2 className="w-5 h-5" />
          <span className="text-xs font-semibold">{post.reposts}</span>
        </button>

        <button className="flex items-center gap-1.5 text-slate-500 hover:text-slate-700 transition-colors">
          <Share2 className="w-5 h-5" />
          <span className="text-xs font-semibold">Share</span>
        </button>
      </div>
    </div>
  );
};

export default PostCard;

import React, { useState } from 'react';
import { Image, Send, Sparkles, Loader2 } from 'lucide-react';
import { refinePostText } from '../services/geminiService';

interface CreatePostProps {
  onPost: (content: string) => void;
}

const CreatePost: React.FC<CreatePostProps> = ({ onPost }) => {
  const [content, setContent] = useState('');
  const [isRefining, setIsRefining] = useState(false);

  const handleRefine = async () => {
    if (!content.trim()) return;
    setIsRefining(true);
    const refined = await refinePostText(content);
    if (refined) {
      setContent(refined);
    }
    setIsRefining(false);
  };

  const handleSubmit = () => {
    if (!content.trim()) return;
    onPost(content);
    setContent('');
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4 mb-6 shadow-sm">
      <div className="flex gap-3 items-start">
        <img src="https://picsum.photos/id/64/100/100" className="w-10 h-10 rounded-lg shrink-0" alt="Avatar" />
        <div className="flex-1">
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder="What's brewing in your tech world?"
            className="w-full bg-transparent border-none focus:ring-0 text-slate-800 placeholder:text-slate-400 min-h-[100px] resize-none text-sm py-2"
          />

          <div className="flex items-center justify-between pt-3 border-t border-slate-100">
            <div className="flex gap-2">
              <button className="p-2 text-slate-400 hover:bg-slate-50 hover:text-slate-600 rounded-lg transition-colors">
                <Image className="w-5 h-5" />
              </button>
              <button 
                onClick={handleRefine}
                disabled={isRefining || !content}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ${
                  content ? 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100' : 'bg-slate-50 text-slate-300'
                }`}
              >
                {isRefining ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                Refine with AI
              </button>
            </div>

            <button
              onClick={handleSubmit}
              disabled={!content.trim()}
              className={`px-6 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${
                content.trim() ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-md shadow-blue-100' : 'bg-slate-100 text-slate-400 cursor-not-allowed'
              }`}
            >
              Post <Send className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CreatePost;

