import React, { useState } from 'react';
import { Send, Sparkles, Loader2, Lightbulb } from 'lucide-react';
import { refinePostText } from '../services/geminiService';

interface CreatePitchProps {
  onPitch: (title: string, description: string, category: string) => void;
}

const CreatePitch: React.FC<CreatePitchProps> = ({ onPitch }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('SaaS');
  const [isRefining, setIsRefining] = useState(false);

  const handleRefine = async () => {
    if (!description.trim()) return;
    setIsRefining(true);
    const refined = await refinePostText(`Help me refine this startup pitch: Title: ${title}. Description: ${description}`);
    if (refined) {
      setDescription(refined);
    }
    setIsRefining(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || !description.trim()) return;
    onPitch(title, description, category);
    setTitle('');
    setDescription('');
  };

  return (
    <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl p-6 mb-8 text-white shadow-xl shadow-blue-200">
      <div className="flex items-center gap-3 mb-6">
        <div className="bg-white/20 p-2 rounded-xl backdrop-blur-sm">
          <Lightbulb className="w-6 h-6 text-amber-300" />
        </div>
        <div>
          <h2 className="text-xl font-black">Pitch your next big thing</h2>
          <p className="text-blue-100 text-xs">Get validation and feedback from top founders.</p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <input
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Startup Name / Catchy Title"
            className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 placeholder:text-blue-200 text-white focus:outline-none focus:ring-2 focus:ring-white/30 transition-all font-bold"
          />
        </div>

        <div>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Describe the problem, solution, and vision..."
            className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 placeholder:text-blue-200 text-white focus:outline-none focus:ring-2 focus:ring-white/30 transition-all min-h-[120px] resize-none text-sm"
          />
        </div>

        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 pt-2">
          <select 
            value={category}
            onChange={(e) => setCategory(e.target.value)}
            className="bg-white/10 border border-white/20 rounded-xl px-4 py-2 text-xs font-bold text-white focus:outline-none w-full sm:w-auto"
          >
            <option value="SaaS" className="text-slate-900">SaaS</option>
            <option value="Hardware" className="text-slate-900">Hardware</option>
            <option value="Fintech" className="text-slate-900">Fintech</option>
            <option value="AI" className="text-slate-900">AI / ML</option>
            <option value="EdTech" className="text-slate-900">EdTech</option>
          </select>

          <div className="flex items-center gap-3 w-full sm:w-auto">
            <button
              type="button"
              onClick={handleRefine}
              disabled={isRefining || !description}
              className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl bg-white/20 hover:bg-white/30 text-white text-xs font-bold transition-all disabled:opacity-50"
            >
              {isRefining ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
              AI Refine
            </button>
            <button
              type="submit"
              disabled={!title.trim() || !description.trim()}
              className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-2.5 rounded-xl bg-white text-blue-600 hover:bg-blue-50 text-xs font-black transition-all disabled:opacity-50 shadow-lg"
            >
              Pitch Idea <Send className="w-4 h-4" />
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

export default CreatePitch;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Sidebar from './components/Sidebar';
import RightPanel from './components/RightPanel';
import PostCard from './components/PostCard';
import CreatePost from './components/CreatePost';
import PitchCard from './components/PitchCard';
import CreatePitch from './components/CreatePitch';
import { INITIAL_POSTS, CURRENT_USER, INITIAL_PITCHES } from './constants';
import { Post, Pitch } from './types';
import { Rocket } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'launchpad'>('home');
  const [posts, setPosts] = useState<Post[]>(INITIAL_POSTS);
  const [pitches, setPitches] = useState<Pitch[]>(INITIAL_PITCHES);

  const handleNewPost = (content: string) => {
    const newPost: Post = {
      id: `p${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      content,
      likes: 0,
      comments: 0,
      reposts: 0,
      timestamp: 'Just now',
      tags: []
    };
    setPosts([newPost, ...posts]);
  };

  const handleNewPitch = (title: string, description: string, category: string) => {
    const newPitch: Pitch = {
      id: `pitch${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      title,
      description,
      votes: 0,
      category,
      timestamp: 'Just now',
      votedBy: []
    };
    setPitches([newPitch, ...pitches]);
  };

  const handleVote = (id: string) => {
    setPitches(prevPitches => {
      return prevPitches.map(pitch => {
        if (pitch.id === id) {
          const hasVoted = pitch.votedBy.includes(CURRENT_USER.id);
          if (hasVoted) {
            // Remove vote
            return {
              ...pitch,
              votes: pitch.votes - 1,
              votedBy: pitch.votedBy.filter(uid => uid !== CURRENT_USER.id)
            };
          } else {
            // Add vote
            return {
              ...pitch,
              votes: pitch.votes + 1,
              votedBy: [...pitch.votedBy, CURRENT_USER.id]
            };
          }
        }
        return pitch;
      });
    });
  };

  // Sort pitches by votes (top voted on top)
  const sortedPitches = [...pitches].sort((a, b) => b.votes - a.votes);

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {/* Left Sidebar */}
      <Sidebar />

      {/* Main Content */}
      <div className="md:col-span-8 lg:col-span-6 pb-20 md:pb-0">
        {activeTab === 'home' ? (
          <>
            <div className="flex items-center justify-between mb-4 px-1">
              <h2 className="text-lg font-bold text-slate-900">Your Feed</h2>
              <div className="flex gap-2">
                <button className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full">For You</button>
                <button className="text-xs font-bold text-slate-500 hover:text-slate-800 px-3 py-1.5 transition-colors">Following</button>
              </div>
            </div>

            <CreatePost onPost={handleNewPost} />

            <div className="space-y-4">
              {posts.map(post => (
                <PostCard key={post.id} post={post} />
              ))}
            </div>
          </>
        ) : (
          <>
            <div className="flex items-center justify-between mb-6 px-1">
              <div className="flex items-center gap-2">
                <div className="p-2 bg-blue-600 rounded-lg">
                  <Rocket className="w-5 h-5 text-white" />
                </div>
                <h2 className="text-xl font-black text-slate-900">Launchpad</h2>
              </div>
              <div className="flex gap-2">
                <button className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full">Top Voted</button>
                <button className="text-xs font-bold text-slate-500 hover:text-slate-800 px-3 py-1.5 transition-colors">Newest</button>
              </div>
            </div>

            <CreatePitch onPitch={handleNewPitch} />

            <div className="space-y-4">
              {sortedPitches.map((pitch, index) => (
                <PitchCard 
                  key={pitch.id} 
                  pitch={pitch} 
                  onVote={handleVote} 
                  rank={index + 1}
                />
              ))}
            </div>

            {pitches.length === 0 && (
              <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-200">
                <div className="inline-block p-4 bg-slate-50 rounded-full mb-4">
                  <Rocket className="w-10 h-10 text-slate-300" />
                </div>
                <p className="text-slate-500 font-bold">The launchpad is clear.</p>
                <p className="text-slate-400 text-xs mt-1">Be the first to pitch your idea to the world!</p>
              </div>
            )}
          </>
        )}
      </div>

      {/* Right Panel */}
      <RightPanel />
    </Layout>
  );
};

