                  Top Voted
                </button>
                <button 
                  onClick={() => setPitchSort('newest')}
                  className={`text-[10px] font-bold px-3 py-1.5 rounded-lg transition-all ${pitchSort === 'newest' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Newest
                </button>
                <button 
                  onClick={() => setPitchSort('random')}
                  className={`text-[10px] font-bold px-3 py-1.5 rounded-lg transition-all flex items-center gap-1 ${pitchSort === 'random' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  <Shuffle className="w-3 h-3" /> Random
                </button>
              </div>
            </div>

            <CreatePitch onPitch={handleNewPitch} />

            <div className="space-y-4">
              {sortedPitches.map((pitch, index) => (
                <PitchCard 
                  key={pitch.id} 
                  pitch={pitch} 
                  onVote={handleVote} 
                  rank={pitchSort === 'top' ? index + 1 : undefined}
                />
              ))}
            </div>

            {pitches.length === 0 && (
              <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-200">
                <div className="inline-block p-4 bg-slate-50 rounded-full mb-4">
                  <Rocket className="w-10 h-10 text-slate-300" />
                </div>
                <p className="text-slate-500 font-bold">The launchpad is clear.</p>
                <p className="text-slate-400 text-xs mt-1">Be the first to pitch your idea to the world!</p>
              </div>
            )}
          </>
        )}
      </div>

      {/* Right Panel */}
      <RightPanel />
    </Layout>
  );
};

export default App;

