                <img src={activeChat.participant.avatar} className="w-10 h-10 rounded-xl object-cover" alt={activeChat.participant.name} />
                <div>
                  <h3 className="text-sm font-bold text-slate-900 leading-none mb-1">{activeChat.participant.name}</h3>
                  <p className="text-[10px] text-green-500 font-bold">Online</p>
