              {activeChat.messages.map((msg) => (
                <div 
                  key={msg.id} 
                  className={`flex flex-col max-w-[70%] ${msg.senderId === CURRENT_USER.id ? 'ml-auto items-end' : 'items-start'}`}
                >
                  <div className={`px-4 py-2.5 rounded-2xl text-sm leading-relaxed shadow-sm ${msg.senderId === CURRENT_USER.id ? 'bg-blue-600 text-white rounded-tr-none' : 'bg-slate-100 text-slate-800 rounded-tl-none'}`}>
