import React, { useState } from 'react';
import { Post, PostComment } from '../types';
import { Heart, MessageCircle, Repeat2, Share2, MoreHorizontal, Send, UserPlus } from 'lucide-react';
import { CURRENT_USER } from '../constants';

interface PostCardProps {
  post: Post;
}

const PostCard: React.FC<PostCardProps> = ({ post }) => {
  const [liked, setLiked] = useState(false);
  const [likesCount, setLikesCount] = useState(post.likes);
  const [expandedSection, setExpandedSection] = useState<'comments' | 'reposts' | null>(null);
  const [newComment, setNewComment] = useState('');
  const [comments, setComments] = useState<PostComment[]>(post.commentList || []);

  const handleLike = () => {
    if (liked) {
      setLikesCount(prev => prev - 1);
    } else {
      setLikesCount(prev => prev + 1);
    }
    setLiked(!liked);
  };

  const toggleSection = (section: 'comments' | 'reposts') => {
    setExpandedSection(prev => prev === section ? null : section);
  };

  const handleAddComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newComment.trim()) return;

    const comment: PostComment = {
      id: `c${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      text: newComment,
      timestamp: 'Just now'
    };

    setComments(prev => [comment, ...prev]);
    setNewComment('');
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 mb-4 overflow-hidden transition-shadow hover:shadow-md">
      {/* Post Content */}
      <div className="p-4">
        <div className="flex items-start justify-between mb-4">
          <div className="flex gap-3">
            <img 
              src={post.user.avatar} 
              alt={post.user.name} 
              className="w-12 h-12 rounded-lg object-cover"
            />
            <div>
              <h3 className="font-bold text-slate-900 leading-tight">{post.user.name}</h3>
              <p className="text-xs text-slate-500 font-medium">@{post.user.username} • {post.timestamp}</p>
              <p className="text-[10px] text-slate-400 mt-0.5">{post.user.role} @ {post.user.company}</p>
            </div>
          </div>
          <button className="text-slate-400 hover:text-slate-600 transition-colors">
            <MoreHorizontal className="w-5 h-5" />
          </button>
        </div>

        <div className="mb-4">
          <p className="text-sm text-slate-800 leading-relaxed whitespace-pre-wrap">
            {post.content}
          </p>
          <div className="flex flex-wrap gap-1 mt-2">
            {post.tags.map(tag => (
              <span key={tag} className="text-xs text-blue-600 font-medium hover:underline cursor-pointer">
                #{tag}
              </span>
            ))}
          </div>
        </div>

        {post.image && (
          <div className="mb-4 rounded-xl overflow-hidden border border-slate-100">
            <img src={post.image} alt="Post media" className="w-full h-auto object-cover max-h-[400px]" />
          </div>
        )}

        <div className="flex items-center justify-between pt-4 border-t border-slate-50">
          <button 
            onClick={handleLike}
            className={`flex items-center gap-1.5 transition-colors p-2 rounded-lg hover:bg-rose-50 ${liked ? 'text-rose-500' : 'text-slate-500 hover:text-rose-500'}`}
          >
            <Heart className={`w-5 h-5 ${liked ? 'fill-current' : ''}`} />
            <span className="text-xs font-bold">{likesCount}</span>
          </button>

          <button 
            onClick={() => toggleSection('comments')}
            className={`flex items-center gap-1.5 transition-colors p-2 rounded-lg ${expandedSection === 'comments' ? 'text-blue-600 bg-blue-50' : 'text-slate-500 hover:text-blue-500 hover:bg-blue-50'}`}
          >
            <MessageCircle className="w-5 h-5" />
            <span className="text-xs font-bold">{comments.length}</span>
          </button>

          <button 
            onClick={() => toggleSection('reposts')}
            className={`flex items-center gap-1.5 transition-colors p-2 rounded-lg ${expandedSection === 'reposts' ? 'text-green-600 bg-green-50' : 'text-slate-500 hover:text-green-500 hover:bg-green-50'}`}
          >
            <Repeat2 className="w-5 h-5" />
            <span className="text-xs font-bold">{post.reposterList?.length || 0}</span>
          </button>

          <button className="flex items-center gap-1.5 text-slate-500 hover:text-slate-700 hover:bg-slate-50 p-2 rounded-lg transition-colors">
            <Share2 className="w-5 h-5" />
            <span className="text-xs font-bold hidden sm:inline">Share</span>
          </button>
        </div>
      </div>

      {/* Expandable Sections */}
      {expandedSection === 'comments' && (
        <div className="bg-slate-50 border-t border-slate-100 p-4 space-y-4 animate-in slide-in-from-top-2 duration-200">
          {/* New Comment Input */}
          <form onSubmit={handleAddComment} className="flex gap-3 items-center">
            <img src={CURRENT_USER.avatar} className="w-8 h-8 rounded-lg shrink-0" alt="Me" />
            <div className="flex-1 relative">
              <input 
                type="text" 
                value={newComment}
                onChange={(e) => setNewComment(e.target.value)}
                placeholder="Write a comment..." 
                className="w-full bg-white border border-slate-200 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none pr-10"
              />
              <button 
                type="submit"
                disabled={!newComment.trim()}
                className="absolute right-2 top-1/2 -translate-y-1/2 text-blue-600 disabled:text-slate-300 transition-colors"
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
          </form>

          {/* Comments List */}
          <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
            {comments.length > 0 ? (
              comments.map(comment => (
                <div key={comment.id} className="flex gap-3 items-start group">
                  <img src={comment.user.avatar} className="w-8 h-8 rounded-lg shrink-0 object-cover" alt={comment.user.name} />
                  <div className="flex-1 bg-white p-3 rounded-2xl rounded-tl-none border border-slate-100 shadow-sm group-hover:border-blue-100 transition-colors">
                    <div className="flex items-center justify-between mb-1">
                      <h4 className="text-xs font-bold text-slate-900">{comment.user.name}</h4>
                      <span className="text-[10px] text-slate-400">{comment.timestamp}</span>
                    </div>
                    <p className="text-xs text-slate-600 leading-relaxed">{comment.text}</p>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-6 text-slate-400 text-xs italic">
                No comments yet. Be the first to start the conversation!
              </div>
            )}
          </div>
        </div>
      )}

      {expandedSection === 'reposts' && (
        <div className="bg-slate-50 border-t border-slate-100 p-4 animate-in slide-in-from-top-2 duration-200">
          <h4 className="text-xs font-black text-slate-900 mb-4 uppercase tracking-wider">Reposted by</h4>
          <div className="space-y-3">
            {post.reposterList && post.reposterList.length > 0 ? (
              post.reposterList.map(reposter => (
                <div key={reposter.id} className="flex items-center justify-between bg-white p-3 rounded-xl border border-slate-100 shadow-sm hover:border-green-100 transition-colors">
                  <div className="flex items-center gap-3">
                    <img src={reposter.avatar} className="w-8 h-8 rounded-lg object-cover" alt={reposter.name} />
                    <div>
                      <p className="text-xs font-bold text-slate-900 leading-none">{reposter.name}</p>
                      <p className="text-[10px] text-slate-500 mt-0.5">@{reposter.username}</p>
                    </div>
                  </div>
                  <button className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors">
                    <UserPlus className="w-4 h-4" />
                  </button>
                </div>
              ))
            ) : (
              <div className="text-center py-6 text-slate-400 text-xs italic">
                No reposts yet.
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default PostCard;

import React, { useState, useMemo } from 'react';
import Layout from './components/Layout';
import Sidebar from './components/Sidebar';
import RightPanel from './components/RightPanel';
import PostCard from './components/PostCard';
import CreatePost from './components/CreatePost';
import PitchCard from './components/PitchCard';
import CreatePitch from './components/CreatePitch';
import MessagingView from './components/MessagingView';
import { INITIAL_POSTS, CURRENT_USER, INITIAL_PITCHES } from './constants';
import { Post, Pitch } from './types';
import { Rocket, Shuffle } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'launchpad' | 'chats'>('home');
  const [posts, setPosts] = useState<Post[]>(INITIAL_POSTS);
  const [pitches, setPitches] = useState<Pitch[]>(INITIAL_PITCHES);
  const [pitchSort, setPitchSort] = useState<'top' | 'newest' | 'random'>('top');

  const handleNewPost = (content: string) => {
    // Fixed: Added missing required properties 'commentList' and 'reposterList' to satisfy the Post interface.
    const newPost: Post = {
      id: `p${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      content,
      likes: 0,
      comments: 0,
      commentList: [],
      reposts: 0,
      reposterList: [],
      timestamp: 'Just now',
      tags: []
    };
    setPosts([newPost, ...posts]);
  };

  const handleNewPitch = (title: string, description: string, category: string) => {
    const newPitch: Pitch = {
      id: `pitch${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      title,
      description,
      votes: 0,
      category,
      timestamp: 'Just now',
      votedBy: []
    };
    setPitches([newPitch, ...pitches]);
  };

  const handleVote = (id: string) => {
    setPitches(prevPitches => {
      return prevPitches.map(pitch => {
        if (pitch.id === id) {
          const hasVoted = pitch.votedBy.includes(CURRENT_USER.id);
          if (hasVoted) {
            return {
              ...pitch,
              votes: pitch.votes - 1,
              votedBy: pitch.votedBy.filter(uid => uid !== CURRENT_USER.id)
            };
          } else {
            return {
              ...pitch,
              votes: pitch.votes + 1,
              votedBy: [...pitch.votedBy, CURRENT_USER.id]
            };
          }
        }
        return pitch;
      });
    });
  };

  // Derived sorted pitches based on selected sort criteria
  const sortedPitches = useMemo(() => {
    const list = [...pitches];
    if (pitchSort === 'top') {
      return list.sort((a, b) => b.votes - a.votes);
    } else if (pitchSort === 'newest') {
      return list.reverse(); 
    } else if (pitchSort === 'random') {
      return list.sort(() => Math.random() - 0.5);
    }
    return list;
  }, [pitches, pitchSort]);

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {activeTab !== 'chats' && <Sidebar />}

      <div className={activeTab === 'chats' ? 'md:col-span-12 h-full' : 'md:col-span-8 lg:col-span-6 pb-20 md:pb-0'}>
        {activeTab === 'home' && (
          <>
            <div className="flex items-center justify-between mb-4 px-1">
              <h2 className="text-lg font-bold text-slate-900">Your Feed</h2>
              <div className="flex gap-2">
                <button className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full">For You</button>
                <button className="text-xs font-bold text-slate-500 hover:text-slate-800 px-3 py-1.5 transition-colors">Following</button>
              </div>
            </div>

            <CreatePost onPost={handleNewPost} />

            <div className="space-y-4">
              {posts.map(post => (
                <PostCard key={post.id} post={post} />
              ))}
            </div>
          </>
        )}

        {activeTab === 'launchpad' && (
          <>
            <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-6 px-1 gap-4">
              <div className="flex items-center gap-2">
                <div className="p-2 bg-blue-600 rounded-lg">
                  <Rocket className="w-5 h-5 text-white" />
                </div>
                <h2 className="text-xl font-black text-slate-900">Launchpad</h2>
              </div>
              <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-xl">
                <button 
                  onClick={() => setPitchSort('top')}
                  className={`text-[10px] font-bold px-3 py-1.5 rounded-lg transition-all ${pitchSort === 'top' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Top Voted
                </button>
                <button 
                  onClick={() => setPitchSort('newest')}
                  className={`text-[10px] font-bold px-3 py-1.5 rounded-lg transition-all ${pitchSort === 'newest' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Newest
                </button>
                <button 
                  onClick={() => setPitchSort('random')}
                  className={`text-[10px] font-bold px-3 py-1.5 rounded-lg transition-all flex items-center gap-1 ${pitchSort === 'random' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  <Shuffle className="w-3 h-3" /> Random
                </button>
              </div>
            </div>

            <CreatePitch onPitch={handleNewPitch} />

            <div className="space-y-4">
              {sortedPitches.map((pitch, index) => (
                <PitchCard 
                  key={pitch.id} 
                  pitch={pitch} 
                  onVote={handleVote} 
                  rank={pitchSort === 'top' ? index + 1 : undefined}
                />
              ))}
            </div>
          </>
        )}

        {activeTab === 'chats' && <MessagingView />}
      </div>

      {activeTab !== 'chats' && <RightPanel />}
    </Layout>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

// Always initialize the GoogleGenAI client with the named apiKey parameter from process.env.API_KEY.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generatePostIdeas = async (topic: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate 3 short, engaging professional post ideas for a tech social network about the topic: ${topic}. Format as a simple list.`,
    });
    // Use the .text property directly to extract text content from the response.
    return response.text;
  } catch (error) {
    console.error("Error generating post ideas:", error);
    return "Could not generate ideas right now. Try again later!";
  }
};

export const refinePostText = async (content: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a professional social media manager for tech experts. Refine this post to be more engaging and concise, keeping it professional but with a 'building in public' vibe. Add 2-3 relevant hashtags: "${content}"`,
    });
    // Use the .text property directly to extract text content from the response.
    return response.text;
  } catch (error) {
    console.error("Error refining post:", error);
    return content;
  }
};

