import React, { useState } from 'react';
import { Send, Sparkles, Loader2, X, Lightbulb } from 'lucide-react';
import { refinePostText } from '../services/geminiService';

interface CreatePitchProps {
  isOpen: boolean;
  onClose: () => void;
  onPitch: (title: string, description: string, category: string) => void;
}

const CreatePitch: React.FC<CreatePitchProps> = ({ isOpen, onClose, onPitch }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('SaaS');
  const [isRefining, setIsRefining] = useState(false);

  if (!isOpen) return null;

  const handleRefine = async () => {
    if (!description.trim()) return;
    setIsRefining(true);
    const refined = await refinePostText(`Help me refine this startup pitch. Title: ${title}. Description: ${description}. Focus on making the problem statement sharp.`);
    if (refined) {
      setDescription(refined);
    }
    setIsRefining(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || !description.trim()) return;
    onPitch(title, description, category);
    setTitle('');
    setDescription('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={onClose} />

      {/* Modal */}
      <div className="relative bg-white w-full max-w-xl rounded-[28px] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
        <div className="bg-blue-600 p-6 flex justify-between items-center text-white">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl">
              <Lightbulb className="w-5 h-5 text-amber-300" />
            </div>
            <div>
              <h2 className="text-lg font-black leading-tight">Submit Your Idea</h2>
              <p className="text-blue-100 text-[10px] font-bold uppercase tracking-wider">The Launchpad</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-5">
          <div>
            <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Startup Name</label>
            <input
              type="text"
              autoFocus
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="e.g. Nexen AI"
              className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 placeholder:text-slate-300 text-slate-900 focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all font-bold"
            />
          </div>

          <div>
            <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">The Problem & Solution</label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Explain the problem you're solving and how your product works..."
              className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 placeholder:text-slate-300 text-slate-900 focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all min-h-[160px] resize-none text-sm font-medium leading-relaxed"
            />
          </div>

          <div className="flex flex-col sm:flex-row items-center justify-between gap-4 pt-4 border-t border-slate-50">
            <div className="w-full sm:w-auto">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1">Category</label>
              <select 
                value={category}
                onChange={(e) => setCategory(e.target.value)}
                className="bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-xs font-bold text-slate-700 focus:outline-none w-full sm:w-40 appearance-none cursor-pointer"
              >
                <option value="SaaS">SaaS</option>
                <option value="DevTools">DevTools</option>
                <option value="Marketplace">Marketplace</option>
                <option value="Fintech">Fintech</option>
                <option value="AI">AI / ML</option>
              </select>
            </div>

            <div className="flex items-center gap-3 w-full sm:w-auto">
              <button
                type="button"
                onClick={handleRefine}
                disabled={isRefining || !description}
                className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-3 rounded-xl bg-indigo-50 text-indigo-600 text-xs font-bold transition-all disabled:opacity-50"
              >
                {isRefining ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                Refine with AI
              </button>
              <button
                type="submit"
                disabled={!title.trim() || !description.trim()}
                className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-8 py-3 rounded-xl bg-blue-600 text-white hover:bg-blue-700 text-xs font-black transition-all disabled:opacity-50 shadow-lg shadow-blue-100"
              >
                Post Idea <Send className="w-4 h-4" />
              </button>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default CreatePitch;

import React, { useState, useMemo } from 'react';
import Layout from './components/Layout';
import Sidebar from './components/Sidebar';
import RightPanel from './components/RightPanel';
import PostCard from './components/PostCard';
import CreatePost from './components/CreatePost';
import PitchCard from './components/PitchCard';
import CreatePitch from './components/CreatePitch';
import MessagingView from './components/MessagingView';
import { INITIAL_POSTS, CURRENT_USER, INITIAL_PITCHES } from './constants';
import { Post, Pitch } from './types';
import { Rocket, Sparkles, TrendingUp } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'launchpad' | 'chats'>('home');
  const [posts, setPosts] = useState<Post[]>(INITIAL_POSTS);
  const [pitches, setPitches] = useState<Pitch[]>(INITIAL_PITCHES);
  const [pitchSort, setPitchSort] = useState<'all' | 'trending'>('all');
  const [isPitchModalOpen, setIsPitchModalOpen] = useState(false);

  const handleNewPost = (content: string) => {
    const newPost: Post = {
      id: `p${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      content,
      likes: 0,
      comments: 0,
      commentList: [],
      reposts: 0,
      reposterList: [],
      timestamp: 'Just now',
      tags: []
    };
    setPosts([newPost, ...posts]);
  };

  const handleNewPitch = (title: string, description: string, category: string) => {
    const newPitch: Pitch = {
      id: `pitch${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      title,
      description,
      votes: 0,
      category,
      timestamp: 'Just now',
      votedBy: [],
      supportersCount: 0,
      isTrending: false
    };
    setPitches([newPitch, ...pitches]);
  };

  const handleVote = (id: string) => {
    setPitches(prevPitches => {
      return prevPitches.map(pitch => {
        if (pitch.id === id) {
          const hasVoted = pitch.votedBy.includes(CURRENT_USER.id);
          if (hasVoted) {
            return {
              ...pitch,
              votes: pitch.votes - 1,
              votedBy: pitch.votedBy.filter(uid => uid !== CURRENT_USER.id)
            };
          } else {
            return {
              ...pitch,
              votes: pitch.votes + 1,
              votedBy: [...pitch.votedBy, CURRENT_USER.id]
            };
          }
        }
        return pitch;
      });
    });
  };

  // Derived sorted pitches based on selected sort criteria
  const sortedPitches = useMemo(() => {
    const list = [...pitches];
    if (pitchSort === 'trending') {
      return list.filter(p => p.isTrending || p.votes > 200).sort((a, b) => b.votes - a.votes);
    }
    return list.sort((a, b) => b.votes - a.votes);
  }, [pitches, pitchSort]);

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {activeTab !== 'chats' && <Sidebar />}

      <div className={activeTab === 'chats' ? 'md:col-span-12 h-full' : 'md:col-span-8 lg:col-span-6 pb-20 md:pb-0'}>
        {activeTab === 'home' && (
          <>
            <div className="flex items-center justify-between mb-4 px-1">
              <h2 className="text-lg font-bold text-slate-900">Your Feed</h2>
              <div className="flex gap-2">
                <button className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full">For You</button>
                <button className="text-xs font-bold text-slate-500 hover:text-slate-800 px-3 py-1.5 transition-colors">Following</button>
              </div>
            </div>

            <CreatePost onPost={handleNewPost} />

            <div className="space-y-4">
              {posts.map(post => (
                <PostCard key={post.id} post={post} />
              ))}
            </div>
          </>
        )}

        {activeTab === 'launchpad' && (
          <>
            <div className="flex items-start justify-between mb-8 px-1">
              <div>
                <h2 className="text-2xl font-black text-slate-900 leading-tight">The Launchpad</h2>
                <p className="text-sm text-slate-500 font-medium mt-1">Discover and support the next big ideas</p>
              </div>
              <button 
                onClick={() => setIsPitchModalOpen(true)}
                className="bg-blue-600 text-white px-5 py-2.5 rounded-xl text-sm font-black flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
              >
                <Sparkles className="w-4 h-4" /> Submit Idea
              </button>
            </div>

            {/* Sorting Tabs */}
            <div className="flex items-center gap-4 mb-8 border-b border-slate-200">
              <button 
                onClick={() => setPitchSort('all')}
                className={`pb-3 text-sm font-bold transition-all relative ${pitchSort === 'all' ? 'text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <div className={`px-4 py-1.5 rounded-lg ${pitchSort === 'all' ? 'bg-blue-600 text-white' : ''}`}>
                  All Ideas
                </div>
              </button>
              <button 
                onClick={() => setPitchSort('trending')}
                className={`pb-3 text-sm font-bold transition-all flex items-center gap-2 relative ${pitchSort === 'trending' ? 'text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <TrendingUp className="w-4 h-4" />
                Trending Ideas
                {pitchSort === 'trending' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-full" />}
              </button>
            </div>

            <CreatePitch 
              isOpen={isPitchModalOpen} 
              onClose={() => setIsPitchModalOpen(false)} 
              onPitch={handleNewPitch} 
            />

            <div className="space-y-4">
              {sortedPitches.map((pitch) => (
                <PitchCard 
                  key={pitch.id} 
                  pitch={pitch} 
                  onVote={handleVote} 
                />
              ))}
            </div>
          </>
        )}

        {activeTab === 'chats' && <MessagingView />}
      </div>

      {activeTab !== 'chats' && <RightPanel />}
    </Layout>
  );
};

export default App;

