                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <div className="flex items-center gap-1.5">
                          <h4 className="text-sm font-bold text-slate-900 truncate">{comment.user.name}</h4>
                          <span className="text-[11px] text-slate-400">@{comment.user.username} • {comment.timestamp}</span>
