import React, { useState, useMemo } from 'react';
import Layout from './components/Layout';
import Sidebar from './components/Sidebar';
import RightPanel from './components/RightPanel';
import PostCard from './components/PostCard';
import CreatePost from './components/CreatePost';
import PitchCard from './components/PitchCard';
import CreatePitch from './components/CreatePitch';
import MessagingView from './components/MessagingView';
import { INITIAL_POSTS, CURRENT_USER, INITIAL_PITCHES } from './constants';
import { Post, Pitch } from './types';
import { Rocket, Sparkles, TrendingUp, ChevronLeft } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'launchpad' | 'chats'>('home');
  const [posts, setPosts] = useState<Post[]>(INITIAL_POSTS);
  const [pitches, setPitches] = useState<Pitch[]>(INITIAL_PITCHES);
  const [pitchSort, setPitchSort] = useState<'all' | 'trending'>('all');
  const [isPitchModalOpen, setIsPitchModalOpen] = useState(false);

  const handleNewPost = (content: string) => {
    const newPost: Post = {
      id: `p${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      content,
      likes: 0,
      comments: 0,
      commentList: [],
      reposts: 0,
      reposterList: [],
      timestamp: 'Just now',
      tags: []
    };
    setPosts([newPost, ...posts]);
  };

  const handleNewPitch = (title: string, description: string, category: string) => {
    const newPitch: Pitch = {
      id: `pitch${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      title,
      description,
      votes: 0,
      category,
      timestamp: 'Just now',
      votedBy: [],
      supportersCount: 0,
      isTrending: false
    };
    setPitches([newPitch, ...pitches]);
  };

  const handleVote = (id: string) => {
    setPitches(prevPitches => {
      return prevPitches.map(pitch => {
        if (pitch.id === id) {
          const hasVoted = pitch.votedBy.includes(CURRENT_USER.id);
          if (hasVoted) {
            return {
              ...pitch,
              votes: pitch.votes - 1,
              votedBy: pitch.votedBy.filter(uid => uid !== CURRENT_USER.id)
            };
          } else {
            return {
              ...pitch,
              votes: pitch.votes + 1,
              votedBy: [...pitch.votedBy, CURRENT_USER.id]
            };
          }
        }
        return pitch;
      });
    });
  };

  const handleBack = () => setActiveTab('home');

  // Derived sorted pitches based on selected sort criteria
  const sortedPitches = useMemo(() => {
    const list = [...pitches];
    if (pitchSort === 'trending') {
      return list.filter(p => p.isTrending || p.votes > 200).sort((a, b) => b.votes - a.votes);
    }
    return list.sort((a, b) => b.votes - a.votes);
  }, [pitches, pitchSort]);

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {activeTab !== 'chats' && <Sidebar activeTab={activeTab} onTabChange={setActiveTab} />}

      <div className={activeTab === 'chats' ? 'md:col-span-12 h-full' : 'md:col-span-8 lg:col-span-6 pb-20 md:pb-0'}>
        {activeTab === 'home' && (
          <>
            <div className="flex items-center justify-between mb-4 px-1">
              <h2 className="text-lg font-black text-slate-900">Your Feed</h2>
              <div className="flex gap-2">
                <button className="text-[10px] font-black uppercase tracking-wider text-blue-600 bg-blue-50 px-3 py-1.5 rounded-xl border border-blue-100">For You</button>
                <button className="text-[10px] font-black uppercase tracking-wider text-slate-500 hover:text-slate-800 px-3 py-1.5 transition-colors">Following</button>
              </div>
            </div>

            <CreatePost onPost={handleNewPost} />

            <div className="space-y-4">
              {posts.map(post => (
                <PostCard key={post.id} post={post} />
              ))}
            </div>
          </>
        )}

        {activeTab === 'launchpad' && (
          <>
            <div className="flex items-center gap-3 mb-6">
              <button 
                onClick={handleBack}
                className="p-2 hover:bg-white rounded-full transition-colors border border-transparent hover:border-slate-200"
              >
                <ChevronLeft className="w-5 h-5 text-slate-600" />
              </button>
              <div>
                <h2 className="text-xl font-black text-slate-900 leading-tight">The Launchpad</h2>
                <p className="text-xs text-slate-500 font-medium">Discover the next big ideas</p>
              </div>
              <button 
                onClick={() => setIsPitchModalOpen(true)}
                className="ml-auto bg-blue-600 text-white px-4 py-2 rounded-xl text-xs font-black flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
              >
                <Sparkles className="w-4 h-4" /> Submit
              </button>
            </div>

            {/* Sorting Tabs */}
            <div className="flex items-center gap-4 mb-6 border-b border-slate-200">
              <button 
                onClick={() => setPitchSort('all')}
                className={`pb-3 text-xs font-bold transition-all relative ${pitchSort === 'all' ? 'text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <div className={`px-4 py-1.5 rounded-xl ${pitchSort === 'all' ? 'bg-blue-600 text-white shadow-md' : ''}`}>
                  All Ideas
                </div>
              </button>
              <button 
                onClick={() => setPitchSort('trending')}
                className={`pb-3 text-xs font-bold transition-all flex items-center gap-2 relative ${pitchSort === 'trending' ? 'text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <TrendingUp className="w-3.5 h-3.5" />
                Trending
                {pitchSort === 'trending' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-full" />}
              </button>
            </div>

            <CreatePitch 
              isOpen={isPitchModalOpen} 
              onClose={() => setIsPitchModalOpen(false)} 
              onPitch={handleNewPitch} 
            />

            <div className="space-y-4">
              {sortedPitches.map((pitch) => (
                <PitchCard 
                  key={pitch.id} 
                  pitch={pitch} 
                  onVote={handleVote} 
                />
              ))}
            </div>
          </>
        )}

        {activeTab === 'chats' && <MessagingView onBack={handleBack} />}
      </div>

      {activeTab !== 'chats' && <RightPanel />}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Chat, Message } from '../types';
import { INITIAL_CHATS, CURRENT_USER } from '../constants';
import { Search, Send, Phone, Video, Info, MoreVertical, ChevronLeft } from 'lucide-react';

interface MessagingViewProps {
  onBack?: () => void;
}

const MessagingView: React.FC<MessagingViewProps> = ({ onBack }) => {
  const [chats, setChats] = useState<Chat[]>(INITIAL_CHATS);
  const [selectedChatId, setSelectedChatId] = useState<string>(INITIAL_CHATS[0].id);
  const [newMessage, setNewMessage] = useState('');

  const activeChat = chats.find(c => c.id === selectedChatId);

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() || !activeChat) return;

    const msg: Message = {
      id: `m${Date.now()}`,
      senderId: CURRENT_USER.id,
      text: newMessage,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };

    const updatedChats = chats.map(c => {
      if (c.id === selectedChatId) {
        return {
          ...c,
          messages: [...c.messages, msg],
          lastMessage: newMessage
        };
      }
      return c;
    });

    setChats(updatedChats);
    setNewMessage('');
  };

  return (
    <div className="md:col-span-12 h-full flex bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
      {/* Sidebar - Chat List */}
      <div className="w-full md:w-80 lg:w-96 border-r border-slate-100 flex flex-col h-full bg-slate-50/30">
        <div className="p-4 bg-white border-b border-slate-100">
          <div className="flex items-center gap-3 mb-4">
            {onBack && (
              <button 
                onClick={onBack}
                className="p-1.5 hover:bg-slate-100 rounded-full transition-colors border border-slate-100"
              >
                <ChevronLeft className="w-4 h-4 text-slate-600" />
              </button>
            )}
            <h2 className="text-lg font-black text-slate-900">Messages</h2>
          </div>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search messages..." 
              className="w-full pl-9 pr-4 py-2 bg-slate-100 border-none rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto">
          {chats.map(chat => (
            <div 
              key={chat.id} 
              onClick={() => setSelectedChatId(chat.id)}
              className={`flex items-center gap-3 p-4 cursor-pointer transition-colors border-l-4 ${selectedChatId === chat.id ? 'bg-white border-blue-600' : 'bg-transparent border-transparent hover:bg-slate-100/50'}`}
            >
              <div className="relative">
                <img src={chat.participant.avatar} className="w-12 h-12 rounded-xl object-cover" alt={chat.participant.name} />
                <div className="absolute -bottom-1 -right-1 w-3.5 h-3.5 bg-green-500 border-2 border-white rounded-full"></div>
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center justify-between mb-0.5">
                  <h3 className="text-sm font-bold text-slate-900 truncate">{chat.participant.name}</h3>
                  <span className="text-[10px] text-slate-400 font-medium">10:35 AM</span>
                </div>
                <p className="text-xs text-slate-500 truncate">{chat.lastMessage}</p>
              </div>
              {chat.unreadCount > 0 && (
                <div className="w-5 h-5 bg-blue-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center">
                  {chat.unreadCount}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Main Chat Area */}
      <div className="hidden md:flex flex-1 flex-col h-full bg-white relative">
        {activeChat ? (
          <>
            {/* Chat Header */}
            <div className="flex items-center justify-between p-4 border-b border-slate-100 bg-white/80 backdrop-blur-md sticky top-0 z-10">
              <div className="flex items-center gap-3">
                <img src={activeChat.participant.avatar} className="w-10 h-10 rounded-xl object-cover" alt={activeChat.participant.name} />
                <div>
                  <h3 className="text-sm font-bold text-slate-900 leading-none mb-1">{activeChat.participant.name}</h3>
                  <p className="text-[10px] text-green-500 font-bold">Online</p>
                </div>
              </div>
              <div className="flex items-center gap-4 text-slate-400">
                <button className="hover:text-blue-600 transition-colors"><Phone className="w-5 h-5" /></button>
                <button className="hover:text-blue-600 transition-colors"><Video className="w-5 h-5" /></button>
                <button className="hover:text-blue-600 transition-colors"><Info className="w-5 h-5" /></button>
                <button className="hover:text-blue-600 transition-colors"><MoreVertical className="w-5 h-5" /></button>
              </div>
            </div>

            {/* Messages List */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6 flex flex-col scroll-smooth">
              {activeChat.messages.map((msg) => (
                <div 
                  key={msg.id} 
                  className={`flex flex-col max-w-[70%] ${msg.senderId === CURRENT_USER.id ? 'ml-auto items-end' : 'items-start'}`}
                >
                  <div className={`px-4 py-2.5 rounded-2xl text-sm leading-relaxed shadow-sm ${msg.senderId === CURRENT_USER.id ? 'bg-blue-600 text-white rounded-tr-none' : 'bg-slate-100 text-slate-800 rounded-tl-none'}`}>
                    {msg.text}
