                    className="w-full bg-slate-50 border-slate-100 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all pr-12"
                  />
                  <div className="absolute right-3 top-1/2 -translate-y-1/2 flex gap-2">
                    {/* Add emoji or attachment icons here if desired */}
                  </div>
                </div>
                <button 
                  type="submit"
                  disabled={!newMessage.trim()}
                  className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 disabled:opacity-50 disabled:shadow-none"
                >
                  <Send className="w-5 h-5" />
                </button>
              </form>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center p-12 text-center text-slate-400">
            <div className="bg-slate-50 p-6 rounded-full mb-4">
              <Send className="w-12 h-12 text-slate-200" />
            </div>
            <h3 className="text-lg font-bold text-slate-600">Your Messages</h3>
            <p className="text-sm max-w-xs mt-2">Connect with founders, investors, and fellow builders. Select a conversation to get started.</p>
          </div>
        )}
      </div>
    </div>
  );
};

