import React, { useState } from 'react';
import { Post, PostComment } from '../types';
import { Heart, MessageCircle, Repeat2, Share2, MoreHorizontal, Send, UserPlus } from 'lucide-react';
import { CURRENT_USER } from '../constants';

interface PostCardProps {
  post: Post;
}

const PostCard: React.FC<PostCardProps> = ({ post }) => {
  const [liked, setLiked] = useState(false);
  const [likesCount, setLikesCount] = useState(post.likes);
  const [expandedSection, setExpandedSection] = useState<'comments' | 'reposts' | null>(null);
  const [newComment, setNewComment] = useState('');
  const [comments, setComments] = useState<PostComment[]>(post.commentList || []);

  const handleLike = () => {
    if (liked) {
      setLikesCount(prev => prev - 1);
    } else {
      setLikesCount(prev => prev + 1);
    }
    setLiked(!liked);
  };

  const toggleSection = (section: 'comments' | 'reposts') => {
    setExpandedSection(prev => prev === section ? null : section);
  };

  const handleAddComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newComment.trim()) return;

    const comment: PostComment = {
      id: `c${Date.now()}`,
      userId: CURRENT_USER.id,
      user: CURRENT_USER,
      text: newComment,
      timestamp: 'Just now'
    };

    setComments(prev => [comment, ...prev]);
    setNewComment('');
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 mb-4 overflow-hidden transition-shadow hover:shadow-md">
      {/* Post Content */}
      <div className="p-4 pb-2">
        <div className="flex items-start justify-between mb-3">
          <div className="flex gap-3">
            <div className="relative">
              <img 
                src={post.user.avatar} 
                alt={post.user.name} 
                className="w-12 h-12 rounded-lg object-cover relative z-10"
              />
              {/* Thread line connecting to comments - Bright Blue */}
              {expandedSection === 'comments' && (
                <div className="absolute top-12 bottom-[-16px] left-1/2 -translate-x-1/2 w-[2px] bg-blue-400 z-0"></div>
              )}
            </div>
            <div>
              <div className="flex items-center gap-1.5">
                <h3 className="font-bold text-slate-900 leading-tight">{post.user.name}</h3>
                <span className="text-xs text-slate-400 font-medium">@{post.user.username} • {post.timestamp}</span>
              </div>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{post.user.role} @ {post.user.company}</p>
            </div>
          </div>
          <button className="text-slate-400 hover:text-slate-600 transition-colors">
            <MoreHorizontal className="w-5 h-5" />
          </button>
        </div>

        <div className="pl-[60px] mb-4">
          <p className="text-sm text-slate-800 leading-relaxed whitespace-pre-wrap">
            {post.content}
          </p>
          <div className="flex flex-wrap gap-1 mt-3">
            {post.tags.map(tag => (
              <span key={tag} className="text-xs text-blue-600 font-medium hover:underline cursor-pointer">
                #{tag}
              </span>
            ))}
          </div>

          {post.image && (
            <div className="mt-4 rounded-xl overflow-hidden border border-slate-100">
              <img src={post.image} alt="Post media" className="w-full h-auto object-cover max-h-[400px]" />
            </div>
          )}
        </div>

        <div className="flex items-center justify-between pt-2 border-t border-slate-50">
          <button 
            onClick={handleLike}
            className={`flex items-center gap-1.5 transition-colors p-2 rounded-lg hover:bg-rose-50 ${liked ? 'text-rose-500' : 'text-slate-500 hover:text-rose-500'}`}
          >
            <Heart className={`w-5 h-5 ${liked ? 'fill-current' : ''}`} />
            <span className="text-xs font-bold">{likesCount}</span>
          </button>

          <button 
            onClick={() => toggleSection('comments')}
            className={`flex items-center gap-1.5 transition-colors p-2 rounded-lg ${expandedSection === 'comments' ? 'text-blue-600 bg-blue-50' : 'text-slate-500 hover:text-blue-500 hover:bg-blue-50'}`}
          >
            <MessageCircle className="w-5 h-5" />
            <span className="text-xs font-bold">{comments.length}</span>
          </button>

          <button 
            onClick={() => toggleSection('reposts')}
            className={`flex items-center gap-1.5 transition-colors p-2 rounded-lg ${expandedSection === 'reposts' ? 'text-green-600 bg-green-50' : 'text-slate-500 hover:text-green-500 hover:bg-green-50'}`}
          >
            <Repeat2 className="w-5 h-5" />
            <span className="text-xs font-bold">{post.reposterList?.length || 0}</span>
          </button>

          <button className="flex items-center gap-1.5 text-slate-500 hover:text-slate-700 hover:bg-slate-50 p-2 rounded-lg transition-colors">
            <Share2 className="w-5 h-5" />
            <span className="text-xs font-bold hidden sm:inline">Share</span>
          </button>
        </div>
      </div>

      {/* Twitter-style Reply Section */}
      {expandedSection === 'comments' && (
        <div className="border-t border-slate-100 animate-in slide-in-from-top-2 duration-200">
          {/* Reply Input Area */}
          <div className="p-4 flex gap-3 relative">
            {/* Thread line connecting - Bright Blue */}
            <div className="absolute top-0 bottom-0 left-[34px] w-[2px] bg-blue-400 z-0"></div>
            <img src={CURRENT_USER.avatar} className="w-10 h-10 rounded-lg shrink-0 z-10" alt="Me" />
            <div className="flex-1">
              <p className="text-[11px] text-slate-400 mb-2 font-medium">
                Replying to <span className="text-blue-600">@{post.user.username}</span>
              </p>
              <form onSubmit={handleAddComment} className="relative">
                <textarea 
                  value={newComment}
                  onChange={(e) => setNewComment(e.target.value)}
                  placeholder="Post your reply" 
                  className="w-full bg-transparent border-none text-sm focus:ring-0 outline-none resize-none min-h-[40px] text-slate-800 placeholder:text-slate-400"
                  rows={1}
                />
                <div className="flex justify-end mt-2 pt-2 border-t border-slate-50">
                  <button 
                    type="submit"
                    disabled={!newComment.trim()}
                    className="bg-blue-600 text-white px-4 py-1.5 rounded-full text-xs font-black disabled:opacity-50 transition-all shadow-sm hover:bg-blue-700"
                  >
                    Reply
                  </button>
                </div>
              </form>
            </div>
          </div>

          {/* Comments List */}
          <div className="max-h-[500px] overflow-y-auto custom-scrollbar">
            {comments.length > 0 ? (
              comments.map((comment, index) => (
                <div key={comment.id} className="group relative">
                  {/* Vertical Line for threading - Bright Blue */}
                  {index !== comments.length - 1 && (
                    <div className="absolute top-14 bottom-0 left-[34px] w-[2px] bg-blue-400 z-0"></div>
                  )}
                  <div className="flex gap-3 items-start px-4 py-4">
                    <img src={comment.user.avatar} className="w-10 h-10 rounded-lg shrink-0 object-cover z-10" alt={comment.user.name} />
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <div className="flex items-center gap-1.5">
                          <h4 className="text-sm font-bold text-slate-900 truncate">{comment.user.name}</h4>
                          <span className="text-[11px] text-slate-400">@{comment.user.username} • {comment.timestamp}</span>
                        </div>
                        <button className="text-slate-300 group-hover:text-slate-400">
                          <MoreHorizontal className="w-4 h-4" />
                        </button>
                      </div>
                      <p className="text-sm text-slate-600 leading-relaxed">{comment.text}</p>

                      <div className="flex items-center gap-6 mt-3 text-slate-400">
                        <button className="hover:text-blue-500 transition-colors flex items-center gap-1">
                          <MessageCircle className="w-3.5 h-3.5" />
                          <span className="text-[10px] font-bold">0</span>
                        </button>
                        <button className="hover:text-green-500 transition-colors flex items-center gap-1">
                          <Repeat2 className="w-3.5 h-3.5" />
                          <span className="text-[10px] font-bold">0</span>
                        </button>
                        <button className="hover:text-rose-500 transition-colors flex items-center gap-1">
                          <Heart className="w-3.5 h-3.5" />
                          <span className="text-[10px] font-bold">0</span>
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-10 text-slate-400 text-xs italic bg-slate-50/30">
                No replies yet.
              </div>
            )}
          </div>
        </div>
      )}

      {expandedSection === 'reposts' && (
        <div className="bg-slate-50 border-t border-slate-100 p-4 animate-in slide-in-from-top-2 duration-200">
          <h4 className="text-xs font-black text-slate-900 mb-4 uppercase tracking-wider">Reposted by</h4>
          <div className="space-y-3">
            {post.reposterList && post.reposterList.length > 0 ? (
              post.reposterList.map(reposter => (
                <div key={reposter.id} className="flex items-center justify-between bg-white p-3 rounded-xl border border-slate-100 shadow-sm hover:border-green-100 transition-colors">
                  <div className="flex items-center gap-3">
                    <img src={reposter.avatar} className="w-8 h-8 rounded-lg object-cover" alt={reposter.name} />
                    <div>
                      <p className="text-xs font-bold text-slate-900 leading-none">{reposter.name}</p>
                      <p className="text-[10px] text-slate-500 mt-0.5">@{reposter.username}</p>
                    </div>
                  </div>
                  <button className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors">
                    <UserPlus className="w-4 h-4" />
                  </button>
                </div>
              ))
            ) : (
              <div className="text-center py-6 text-slate-400 text-xs italic">
                No reposts yet.
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default PostCard;
